import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import ThemeToggle from './ThemeToggle';
import { 
  Cpu, LayoutDashboard, TrendingUp, LogOut, 
  Terminal, Menu, X, Globe, Archive 
} from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);
  // useTheme call kept to trigger re-renders on toggle
  useTheme(); 

  const handleLogout = () => {
    logout();
    setMobileOpen(false);
    navigate('/login');
  };

  const isActive = (path) => location.pathname === path;

  const navLinkStyle = (path) => ({
    textDecoration: 'none',
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
    fontSize: '11px',
    fontWeight: 700,
    textTransform: 'uppercase',
    letterSpacing: '0.05em',
    padding: '0.5rem 0.75rem',
    borderRadius: '8px',
    transition: 'all 0.2s ease',
    color: isActive(path) ? 'var(--accent-primary)' : 'var(--text-secondary)',
    backgroundColor: isActive(path) ? 'var(--accent-muted)' : 'transparent',
    border: isActive(path) ? '1px solid var(--accent-primary)' : '1px solid transparent',
  });

  return (
    <div style={{ position: 'sticky', top: 0, zIndex: 1000, padding: '1rem' }}>
      <nav style={{
        maxWidth: '1200px',
        margin: '0 auto',
        background: 'var(--surface-glass)',
        backdropFilter: 'blur(16px)',
        border: '1px solid var(--surface-border)',
        borderRadius: '16px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '0.6rem 1.2rem'
      }}>
        <Link to="/" style={{ display: 'flex', alignItems: 'center', gap: '10px', textDecoration: 'none', color: 'var(--text-primary)' }}>
          <Cpu size={20} color="var(--accent-primary)" />
          <span style={{ fontWeight: 800, fontSize: '0.9rem', letterSpacing: '0.1em' }}>FINIFY AI</span>
        </Link>

        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }} className="nav-desktop">
          {user ? (
            <>
              <Link to="/dashboard" style={navLinkStyle('/dashboard')}><LayoutDashboard size={14}/> Dashboard</Link>
              <Link to="/generate" style={navLinkStyle('/generate')}><TrendingUp size={14}/> Strategy</Link>
              <Link to="/live" style={navLinkStyle('/live')}><Globe size={14}/> Live_Pulse</Link>
              <Link to="/vault" style={navLinkStyle('/vault')}><Archive size={14}/> Vault</Link>
              <ThemeToggle />
              <button onClick={handleLogout} style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', padding: '0.5rem' }}>
                <LogOut size={16} />
              </button>
            </>
          ) : (
            <>
              <Link to="/login" style={navLinkStyle('/login')}><Terminal size={14}/> Access</Link>
              <Link to="/register" style={{ ...navLinkStyle('/register'), background: 'var(--accent-primary)', color: '#000' }}>Initialize</Link>
              <ThemeToggle />
            </>
          )}
        </div>
        <button className="nav-mobile-toggle" onClick={() => setMobileOpen(!mobileOpen)} style={{ display: 'none', background: 'none', border: 'none', color: 'var(--text-primary)' }}>
          {mobileOpen ? <X /> : <Menu />}
        </button>
      </nav>
      <style>{`
        @media (max-width: 960px) {
          .nav-desktop { display: none !important; }
          .nav-mobile-toggle { display: block !important; }
        }
      `}</style>
    </div>
  );
};

export default Navbar;
